  }
}

function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Retrieve':
      var l0 = g._getColumnOrder('ma_ktr'), first = true;
      for (var i = 0; i < result.length; i++) {
        var a  = result[i];
        if (check$GridVoucherDetail$EmployeeID(g, l0, a[1])) {
          var ins = true, row = g._rowCount;
			    if (first && row > 0) if (g.blankMemvar(row)) {ins = false; first = false;}
			    if (ins) g._appendRow(null, true);
			    row = g._rowCount;
			    var o = g._getItem(row, l0);
			    o.row = row;
			    insert$GridVoucherDetail$Items(g, row, 'ma_ktr, ten_ktr%l', [a[1], a[2]]);
        }
      }
      break;
    default:
      break;
  }
}
function insert$GridVoucherDetail$Items(g, r, columns, v) {
  var a = columns.split(',');
  for (var i = 0; i < a.length; i++) {
    var l = g._getColumnOrder($func.trim(a[i]));
    g._setItemValue(r, l, v[i]);
  }
}
function check$GridVoucherDetail$EmployeeID(g, c, v) {
  for (var r = 1; r <= g._rowCount; r++) {
    if (g._getItemValue(r, c) == v) return 0;
  }
  return 1;
}
